import{_ as a,o as t,c as r,ak as i}from"./chunks/framework.D-xjpKOc.js";const b=JSON.parse('{"title":"Roadmap - Shimera","description":"","frontmatter":{},"headers":[],"relativePath":"devdoc/roadmap.md","filePath":"devdoc/roadmap.md"}'),o={name:"devdoc/roadmap.md"};function n(s,e,l,d,c,h){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="roadmap-shimera" tabindex="-1">Roadmap - Shimera <a class="header-anchor" href="#roadmap-shimera" aria-label="Permalink to “Roadmap - Shimera”">​</a></h1><h2 id="july-2026-decision-point" tabindex="-1">July 2026 - Decision point <a class="header-anchor" href="#july-2026-decision-point" aria-label="Permalink to “July 2026 - Decision point”">​</a></h2><p>Right now, Shimera has a separate abstraction layer for each backend (OpenGL, SFML, Raylib). The team is testing whether this can be replaced with a single generic architecture that works across any backend. The result determines which path the project follows for the rest of this development cycle.</p><ul><li>Generic architecture works out -&gt; <strong>Plan A</strong></li><li>Doesn&#39;t pan out -&gt; <strong>Plan B</strong> (keep current backend-specific architecture)</li></ul><p><em>Risk: the test drags on or gives ambiguous results -&gt; decision date kept firm so the rest of the schedule isn&#39;t delayed.</em></p><h2 id="plan-a-generic-architecture-works-out" tabindex="-1">Plan A (generic architecture works out) <a class="header-anchor" href="#plan-a-generic-architecture-works-out" aria-label="Permalink to “Plan A (generic architecture works out)”">​</a></h2><table tabindex="0"><thead><tr><th>Period</th><th>Features</th></tr></thead><tbody><tr><td><strong>August</strong></td><td>Refactor the library on a dedicated branch around the new generic architecture</td></tr><tr><td><strong>September</strong></td><td>Integrate <a href="https://shader-slang.org/" target="_blank" rel="noreferrer">Slang</a> into the workflow and migrate existing GLSL shaders to it</td></tr><tr><td><strong>October</strong></td><td>Focus on world-space shaders and materials</td></tr><tr><td><strong>November – February</strong></td><td>Consolidate the library and expand the shader catalog</td></tr></tbody></table><h2 id="plan-b-keep-current-backend-specific-architecture" tabindex="-1">Plan B (keep current backend-specific architecture) <a class="header-anchor" href="#plan-b-keep-current-backend-specific-architecture" aria-label="Permalink to “Plan B (keep current backend-specific architecture)”">​</a></h2><table tabindex="0"><thead><tr><th>Period</th><th>Features</th></tr></thead><tbody><tr><td><strong>August</strong></td><td>Integrate Slang into the workflow and migrate existing GLSL shaders to it</td></tr><tr><td><strong>September</strong></td><td>Implement world-space shaders directly in the current library, if not already done</td></tr><tr><td><strong>October – February</strong></td><td>Same consolidation and shader-catalog work as Plan A</td></tr></tbody></table><h2 id="october-world-space-shaders-materials-both-plans" tabindex="-1">October - World-space shaders &amp; materials (both plans) <a class="header-anchor" href="#october-world-space-shaders-materials-both-plans" aria-label="Permalink to “October - World-space shaders &amp; materials (both plans)”">​</a></h2><ul><li>Fog (linear/exponential/volumetric)</li><li>Water Effect</li><li>PBR</li><li>Refraction / Glass</li></ul><p><em>Technical challenge: these shaders need more GPU resources and a more mature multi-pass rendering architecture than the simple post-processing effects already in place.</em></p><h2 id="november-february-consolidation-shader-catalog-both-plans" tabindex="-1">November - February - Consolidation &amp; shader catalog (both plans) <a class="header-anchor" href="#november-february-consolidation-shader-catalog-both-plans" aria-label="Permalink to “November - February - Consolidation &amp; shader catalog (both plans)”">​</a></h2><p>Remaining post-processing shaders to catch up on:</p><ul><li>Depth of Field, Sobel Filter, Cel Shading, Motion Blur</li><li>SSAO / SSR (if time allows)</li><li>Face Culling / Frustum Culling</li></ul><h3 id="prioritization-if-behind-schedule" tabindex="-1">Prioritization if behind schedule <a class="header-anchor" href="#prioritization-if-behind-schedule" aria-label="Permalink to “Prioritization if behind schedule”">​</a></h3><ol><li>Core library + shaders already in place (non-negotiable)</li><li>World-space / material shaders (October)</li><li>Advanced shaders (PBR, SSAO/SSR, volumetric fog)</li><li>Metal / BGFX (first to be dropped if needed)</li></ol>',17)])])}const u=a(o,[["render",n]]);export{b as __pageData,u as default};
